// 1. Detect Input Sources
const chatInput = $input.item.json.chatInput;
const sessionId = $input.item.json.sessionId;
const query = $input.item.json.query || $input.item.json.body || {};

// 2. Define Comprehensive Dummy Metadata Fallback (from userInfo.json)
const dummyPersonalInfo = {
  full_name: "Venkata Ramana Yamali",
  employee_name: "Venkata Ramana Yamali",
  employee_number: "511256",
  personId: 190395,
  assignmentId: 124324,
  title: "Senior Human Resources Information Systems Specialist",
  job: "Senior Human Resources Information Systems Specialist",
  organization: "قسم تطوير وصيانة الانظمة",
  ministry: "Federal Authority for Government Human Resources (FAHR)",
  location: "الهيئة الاتحادية للموارد البشرية الحكومية- دبي",
  email_address: "venkat@fahr.gov.ae",
  mobile_number: "+971526950282",
  work_number: "+97111234561",
  office_number: "+97111234561",
  gender: "Male",
  marital_status: "Married",
  nationality: "India",
  religion: "Hindu",
  education_level: "PHD",
  date_of_birth: "1990-05-15T00:00:00",
  age: 35,
  experience_years: 10.11,
  join_date: "2015-05-24T00:00:00",
  manager_name: "Asem Ahmad Alawadhi",
  manager_number: "553536",
  supervisor_id: 965246,
  country_of_birth: "United Arab Emirates",
  place_of_birth_en: "Dubai, United Arab Emirates"
};

// 3. Extract and Parse Personal Info (from Webhook incoming request)
let personalInfo = {};
try {
  if (typeof query.personalInfo === 'string') {
    personalInfo = JSON.parse(decodeURIComponent(query.personalInfo));
  } else {
    personalInfo = query.personalInfo || {};
  }
} catch (e) {
  console.error("Failed to parse personalInfo:", e);
  personalInfo = {}; 
}

// 4. Merge with Dummy Data (Dummy acts as default if fields are missing in request)
const finalPersonalInfo = {
  ...dummyPersonalInfo,
  ...personalInfo
};

// 5. Construct Normalized Object
const normalized = {
  // Use Chat Session ID or Webhook Conv ID
  conversationId: sessionId || parseInt(query.conversationId) || 0,

  // Use provided PersonID from request, or from dummy metadata
  personId: parseInt(query.personId) || finalPersonalInfo.personId || 190395,

  avatarId: parseInt(query.avatarId) || 0,
  sessionStart: query.sessionStart === 'true' || query.sessionStart === true || false,
  language: query.language || 'en',

  conversationTitle: query.conversationTitle || (chatInput ? 'Chat Session' : 'New Conversation'),

  // Use Chat Input text or Webhook Message
  conversationMessage: chatInput || query.conversationMessage || '',

  channel: chatInput ? 'WEB_CHAT' : (query.channel || 'UI_MOBILE'),
  inputType: query.inputType || 'TEXT',
  outputType: query.outputType || 'TEXT',

  personalInfo: finalPersonalInfo 
};

// 6. Initialize standard array structures for the flow
normalized.messages = [{
  role: 'user',
  content: normalized.conversationMessage
}];

normalized.chatHistory = [];
normalized.citations = [];
normalized.suggestions = [];

return { json: normalized };

// Greeting Node Logic
const language = $input.item.json.language || 'en';
const personalInfo = $input.item.json.personalInfo || {};

// Extract the name from personalInfo
const name = personalInfo.full_name || 'User';

const greetings = {
  en: `Hello ${name}! How can I assist you today?`,
  ar: `مرحباً ${name}! كيف يمكنني مساعدتك اليوم؟`
};

const greeting = greetings[language] || greetings['en'];

return {
  json: {
    ...$input.item.json,
    messages: [{
      role: 'assistant',
      content: greeting,
      response_agent: 'greeting_agent'
    }],
    route: 'end'
  }
};

// 1. Get current input from Normalize Input
const currentState = $node["Normalize Input"].json;
const currentInputMsg = currentState.conversationMessage;
const conversationId = currentState.conversationId;

// 2. Load Existing History 
// (If using n8n binary/static memory, or an external source. Fallback to empty)
let chatHistory = currentState.chatHistory || []; 

// 3. Filter to keep only the last 9 messages (leaving room for the current user message)
// This ensures the combined total never exceeds 10.
if (chatHistory.length > 9) {
    chatHistory = chatHistory.slice(-9);
}

// 4. Merge History + Current Message into the 'messages' array
const combinedMessages = [
  ...chatHistory.map(m => ({ role: m.role, content: m.content })),
  { role: 'user', content: currentInputMsg }
];

return {
  json: {
    ...currentState,
    chatHistory: chatHistory,
    messages: combinedMessages
  }
};

// Process Guardrail and persist state
const inputState = $node["Normalize Input"].json; 
const rawOutput = $input.item.json.output; 

let llmOutput;
try {
  if (typeof rawOutput === 'string') {
    // 1. Regex to find the FIRST JSON object {} in the string
    // This handles markdown blocks and random text surrounding the JSON
    const jsonMatch = rawOutput.match(/\{[\s\S]*\}/);

    if (jsonMatch) {
      llmOutput = JSON.parse(jsonMatch[0]);
    } else {
      // Fallback if no JSON object is found: treat raw text as the message
      llmOutput = { is_relevant: true, message: rawOutput.trim() };
    }
  } else {
    llmOutput = rawOutput;
  }
} catch (e) {
  console.error("Failed to parse Guardrail JSON:", e);
  // Last resort fallback
  llmOutput = { is_relevant: false, message: "I apologize, I'm having trouble formatting my response. Please try again." };
}

// 2. Map the guardrail specific parameters
const guardrailResponse = {
  is_relevant: llmOutput.is_relevant ?? true,
  requires_auth: llmOutput.requires_auth ?? false,
  allow: llmOutput.allow ?? true,
  message: llmOutput.message || ""
};

// 3. Clone messages and handle logic
const messages = [...(inputState.messages || [])];
let skipVirtualAgent = false;

// Check if Guardrail provided a direct response
if (guardrailResponse.message && guardrailResponse.message.trim() !== "") {
  messages.push({
    role: 'assistant',
    content: guardrailResponse.message,
    response_agent: 'input_guardrail_agent'
  });

  skipVirtualAgent = true;
}

// 4. Define the Route
let targetRoute = 'virtual_agent';

// If we have a direct answer OR the query is not relevant -> End
if (skipVirtualAgent || !guardrailResponse.is_relevant) {
  targetRoute = 'end';
}

return {
  json: {
    ...inputState,
    messages: messages,
    guardrailResponse: guardrailResponse,
    route: targetRoute,
    direct_response_given: skipVirtualAgent 
  }
};

// Process Virtual Agent and persist state
const currentState = $node["Process Guardrail Response"].json;
const aiOutput = $input.item.json.output;

let aiText = "";

// Handle the case where the AI Agent returns a JSON string or object
try {
    if (typeof aiOutput === 'string') {
        // Attempt to parse if it looks like JSON, otherwise use as raw text
        if (aiOutput.trim().startsWith('{')) {
            const parsed = JSON.parse(aiOutput);
            aiText = parsed.response || parsed.output || aiOutput;
        } else {
            aiText = aiOutput;
        }
    } else if (typeof aiOutput === 'object') {
        aiText = aiOutput.response || aiOutput.output || JSON.stringify(aiOutput);
    }
} catch (e) {
    aiText = aiOutput; // Fallback to raw output on parse error
}

// Clone and update the messages array for history persistence
const messages = [...(currentState.messages || [])];
messages.push({
  role: 'assistant',
  content: aiText,
  response_agent: 'virtual_agent'
});

return {
  json: {
    ...currentState,
    messages: messages,
    aiResponse: aiText // Helper field for the Reviewer/Output Guardrail node
  }
};

// Generate contextual suggestions based on conversation
const messages = $input.item.json.messages || [];
const language = $input.item.json.language || 'en';

// Default suggestions based on language
const suggestions = language === 'ar' ? [
  "ما هي سياسة الإجازات؟",
  "كيف يمكنني تقديم طلب؟",
  "أخبرني المزيد عن هذا الموضوع"
] : [
  "What is the leave policy?",
  "How can I submit a request?",
  "Tell me more about this topic"
];

return {
  json: {
    ...$input.item.json,
    suggestions: suggestions
  }
};

// Helper function to safely get node output only if it executed
const getSafeNode = (name) => {
  try {
    return $node[name].json;
  } catch (e) {
    return null;
  }
};

// 1. Check all possible sources of the final state
const reviewer = getSafeNode("Process Reviewer Response");
const guardrail = getSafeNode("Process Guardrail Response");
const greeting = getSafeNode("Greeting Node");

// 2. Select the "Source of Truth" based on which path was taken
// We prioritize them in order of the workflow depth
let sourceState = null;

if (reviewer) {
  sourceState = reviewer;
} else if (guardrail && guardrail.direct_response_given) {
  sourceState = guardrail;
} else if (greeting) {
  sourceState = greeting;
}

// Fallback if something went wrong
if (!sourceState) {
    // If we can't find a source, fallback to the previous node's input
    sourceState = $input.item.json;
}

// 3. Extract data from the selected source
const messages = sourceState.messages || [];
const lastMessage = messages[messages.length - 1];
const suggestions = sourceState.suggestions || [];
const citations = sourceState.citations || [];
const apiCallHistory = sourceState.api_call_history || [];

// 4. Build the final structure
const outputs = [
  {
    type: 'text',
    data: lastMessage?.content || 'No response available',
    referenceData: citations,
    faQsData: suggestions
  }
];

if (apiCallHistory.length > 0) {
  outputs.push({
    type: 'widget',
    data: apiCallHistory
  });
}

// 5. Check if we are responding to the Chat UI or the Webhook
// We look at the 'channel' property from our 'Normalize Input' node
const channel = $node["Normalize Input"]?.json?.channel;

if (channel === 'WEB_CHAT') {
  // If it's the Chat UI, return ONLY the text data string
  // n8n Chat Trigger requires a simple string or an object with 'output' to render bubbles correctly
  return {
    json: {
      output: lastMessage?.content || 'No response available'
    }
  };
}

// Otherwise, return the full JSON structure for Webhook/API
return {
  json: {
    conversationId: sourceState.conversationId ? sourceState.conversationId.toString() : "0",
    success: true,
    outputs: outputs,
    timestamp: new Date().toISOString()
  }
};

// 1. Get the current state from the virtual agent processing node
const currentState = $node["Process Virtual Agent Response"].json;

// 2. Get the output from the reviewer LLM
const rawReview = $input.item.json.output;
let review;

try {
  if (typeof rawReview === 'string') {
    // Clean Markdown code blocks (```json ... ```) and extract only the {} content
    const jsonMatch = rawReview.match(/\{[\s\S]*\}/);
    review = jsonMatch ? JSON.parse(jsonMatch[0]) : JSON.parse(rawReview);
  } else {
    review = rawReview;
  }
} catch (e) {
  console.error("Reviewer output parsing failed:", e);
  review = { 
    raise_ticket: false, 
    final_answer: typeof rawReview === 'string' ? rawReview : "", 
    review_notes: "Parsing failed, used raw output as fallback" 
  };
}

// 3. Extract the final answer and handle ticket logic
let finalAnswerText;
if (review.raise_ticket === true) {
    finalAnswerText = currentState.language === 'ar' 
        ? "عذراً، لم أتمكن من العثور على إجابة دقيقة حالياً. يرجى التواصل مع دعم الهيئة الاتحادية للموارد البشرية."
        : "I apologize, but I couldn't find a precise answer at the moment. Please contact FAHR support for further assistance.";
} else {
    finalAnswerText = review.final_answer || currentState.aiResponse;
}

// 4. UPDATE MEMORY (chatHistory)
// We take existing history and add the current pair: User Message + Final Reviewed Answer
let updatedHistory = [...(currentState.chatHistory || [])];

// Add current interaction
updatedHistory.push({ role: 'user', content: currentState.conversationMessage });
updatedHistory.push({ role: 'assistant', content: finalAnswerText });

// Maintain "Last 10 Messages" only
if (updatedHistory.length > 10) {
    updatedHistory = updatedHistory.slice(-10);
}

// 5. Update the 'messages' array for immediate display in this execution
let messages = [...(currentState.messages || [])];
if (messages.length > 0 && messages[messages.length - 1].role === 'assistant') {
    messages[messages.length - 1].content = finalAnswerText;
}

// 6. Return the synchronized JSON state
return {
  json: {
    ...currentState,
    chatHistory: updatedHistory, // Persistent history for next turn
    messages: messages,          // Current turn history
    review_notes: review.review_notes || "",
    raise_ticket: review.raise_ticket || false,
    final_output_text: finalAnswerText 
  }
};

